import { useMemo, useState } from 'react';

function ProductList({ products }) {
  const [search, setSearch] = useState('');
  const [sortBy, setSortBy] = useState('name');

  // ✅ Recalcula só quando products, search ou sortBy mudam
  const filteredProducts = useMemo(() => {
    console.log('Filtrando...');
    return products
      .filter(p => p.name.toLowerCase().includes(search.toLowerCase()))
      .sort((a, b) => a[sortBy] > b[sortBy] ? 1 : -1);
  }, [products, search, sortBy]);

  return (
    <div>
      <input value={search} onChange={e => setSearch(e.target.value)} />
      {filteredProducts.map(p => <div key={p.id}>{p.name}</div>)}
    </div>
  );
}

import { useCallback, useState, memo } from 'react';

// Filho memoizado: só re-renderiza se props mudarem
const TodoItem = memo(function TodoItem({ todo, onToggle }) {
  console.log('Renderizou:', todo.text);
  return (
    <li onClick={() => onToggle(todo.id)}>
      {todo.done ? '✅' : '⬜'} {todo.text}
    </li>
  );
});

function TodoList() {
  const [todos, setTodos] = useState([
    { id: 1, text: 'Estudar React', done: false },
    { id: 2, text: 'Fazer exercício', done: false },
  ]);

  // ✅ Referência estável — TodoItem não re-renderiza sem necessidade
  const handleToggle = useCallback((id) => {
    setTodos(prev => prev.map(t =>
      t.id === id ? { ...t, done: !t.done } : t
    ));
  }, []);

  return <ul>{todos.map(t => <TodoItem key={t.id} todo={t} onToggle={handleToggle} />)}</ul>;
}
